// Expect an object like { files: [...] }
const files = $json.files || [];
return [{ json: { files, fileCount: files.length } }];

// Simple CSV parser (no external deps)
const csvText = $json.body;
const lines = csvText.trim().split(/\r?\n/);
const headers = lines.shift().split(',');
const records = lines.map(line => {
  const cols = line.split(',');
  const obj = {};
  headers.forEach((h, i) => { obj[h.trim()] = (cols[i] || '').trim(); });
  return obj;
});
return [{ json: { originalFileName: $json.fileName, records } }];

const items = $input.item.records;
const invalid = items.filter(r => !r.id || !r.id.length);
return [{ json: {
  originalFileName: $input.item.originalFileName,
  data: items,
  isValid: invalid.length === 0,
  errors: invalid
}}];
